"use client";

import { useState } from "react";
import { triggerParse } from "@/services/api";
import { RefreshCw } from "lucide-react";
import toast from "react-hot-toast";
import clsx from "clsx";

const SARFTI_LOGO = "";

export default function Header() {
  const [refreshing, setRefreshing] = useState(false);

  const handleRefresh = async () => {
    setRefreshing(true);
    try {
      await triggerParse();
      toast.success("Расписание обновляется...");
    } catch {
      toast.error("Не удалось запустить обновление");
    } finally {
      setTimeout(() => setRefreshing(false), 2000);
    }
  };

  return (
    <header className="header-glass sticky top-0 z-40">
      <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <img
            src={`data:image/png;base64,${SARFTI_LOGO}`}
            alt="СарФТИ"
            className="h-10 w-auto object-contain"
          />
          <div className="h-6 w-px bg-white/20" />
          <span className="text-white/70 text-sm font-light tracking-wide">Поиск аудиторий</span>
        </div>

        <button
          onClick={handleRefresh}
          disabled={refreshing}
          className={clsx(
            "flex items-center gap-2 text-sm text-white/70 hover:text-white",
            "px-4 py-2 rounded-xl border border-white/10 hover:border-white/30",
            "backdrop-blur-sm transition-all duration-200 hover:bg-white/10",
            refreshing && "opacity-50 cursor-not-allowed"
          )}
        >
          <RefreshCw className={clsx("w-4 h-4", refreshing && "animate-spin")} />
          <span className="hidden sm:inline">Обновить</span>
        </button>
      </div>
    </header>
  );
}
